PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT (COUNT(?game) AS ?count)
WHERE {
  VALUES ?year { 1977 1978 2008 2009 }
  ?series wdt:P31 wd:Q1363275 ;
          wdt:P585 ?date ;
          wdt:P710 wd:Q334634 ;
          wdt:P710 wd:Q650840 .
  BIND(YEAR(?date) AS ?seriesYear)
  FILTER(?seriesYear = ?year)
  ?game wdt:P361 ?series ;
        wdt:P1330 ?attendance ;
        wdt:P710 wd:Q334634 ;
        wdt:P710 wd:Q650840 .
  FILTER(xsd:integer(?attendance) > 50000)
}

